import Element from "@/types/elements/Element";

/**
 * Generates a URL for a bullet image based on the provided element and index.
 * @param element - The element containing options for the bullet image.
 * @param index - The index used for generating the bullet image.
 * @returns A URL to the bullet image.
 */
export function getBulletPointLink(element: Element, index: number): string {
  const identifier = getBulletPointIdentifier(element.options.type, index);
  const color = getBulletPointColor(element.options.color, index);

  return `https://www.swedbank.ee/kirjad/pohjad/2021/img/${identifier}_${color}.png`;
}

function getBulletPointIdentifier(bulletType: string, index: number) {
  if (bulletType === "Numbered") return (index).toString();
  if (bulletType === "Lettered") return String.fromCharCode(index + 64).toLowerCase();
  return "bullet";
}

function getBulletPointColor(color: string, index: number) {
  const colors = ['green', 'orange', 'purple', 'yellow', 'tangerine'];
  return color === "Multi-color" ? colors[(index - 1) % 5] : color.toLowerCase();
}
